export enum UserType {
  SUPER_ADMIN = 'SUPER_ADMIN',
  ADMIN = 'ADMIN',
  CROSS_DOMAIN_USER = 'CROSS_DOMAIN_USER',
  DOMAIN_USER = 'DOMAIN_USER'
}

export type DomainMode = 'fusion' | 'switching';

export interface Domain {
  id: string;
  name: string;
  code: string;
  parentId: string | null;
  manager: string;
  businessTypes: string[];
  status: 'active' | 'inactive';
  createTime: string;
  children?: Domain[];
  customerIds?: string[];
  managementMode: DomainMode; // Updated: 'fusion' or 'switching'
  isSuper?: boolean; // New: Identifies the system default super domain
}

export interface Menu {
  id: string;
  name: string;
  type: 'dir' | 'menu' | 'button';
  parentId: string | null;
  path?: string;
  component?: string;
  permission?: string;
  icon?: string;
  sort: number;
  visible: boolean;
  children?: Menu[];
}

export interface Role {
  id: string;
  name: string;
  code: string;
  domainId: string;
  description: string;
  menuIds?: string[]; // Added: Persist menu selections
  regionScope?: string[]; // e.g., ['0551', '0553']
  bizCategoryScope?: string[];
  bizInstanceScope?: string[];
}

export interface UserRoleRelation {
  roleId: string;
  targetDomainId: string;
  roleName?: string; // Optional for UI convenience
}

export interface User {
  id: string;
  username: string;
  realName: string;
  phone: string;
  email: string;
  status: 'active' | 'locked';
  baseDomainId: string;
  createTime: string;
  roles: UserRoleRelation[]; // Support cross-domain roles
}

export interface BusinessInstance {
  id: string;
  name: string;
  categoryCode: string; // e.g., 'BIZ_LINE'
}

// UI Types
export interface NavItem {
  id: string;
  title: string;
  icon: any;
  children?: NavItem[];
}

